noncompliant:
#include <utility>

// Noncompliant - recursive template instantiation
template<class Cont>
void addElementsToContainer(Cont &C) {
  // Base case - do nothing
}

template<class Cont, class T, class ...U>
void addElementsToContainer(Cont &C, T &&t, U &&...us) {
  C.push_back(std::forward<T>(t));
  addElementsToContainer(C, std::forward<U>(us)...); // Noncompliant - recursive call
}

// Another example
template<typename T>
T sum(T t) {
  return t;
}

template<typename T, typename... Args>
T sum(T first, Args... args) {
  return first + sum(args...); // Noncompliant - recursive
}

compliant:
#include <utility>

// Compliant - using fold expression (C++17)
template<class Cont, class ...T>
void addElementsToContainer(Cont &C, T &&...ts) {
  (C.push_back(std::forward<T>(ts)),...); // Compliant fold expression
}

// Another example with fold expression
template<typename... Args>
auto sum(Args... args) {
  return (args + ...); // Compliant - fold expression
}

// Binary fold example
template<typename... Args>
bool all_true(Args... args) {
  return (args && ...); // Compliant - logical AND fold
}
